const items = $input.all();

for (const item of items) {
  // Obtenemos el sector del JSON de Alpha Vantage
  const sector = item.json.Sector || "Unknown";

  let jump_prob, expected_drop, cvar_95;

  // Lógica del Mock: Si es sector contaminante (Brown Asset)
  if (['Energy', 'Utilities', 'Basic Materials', 'Manufacturing'].includes(sector)) {
    jump_prob = 18.5;     // 18.5% de probabilidad de shock climático/regulatorio anual
    expected_drop = 35.0; // Caída estimada del 35% si ocurre el evento
    cvar_95 = 28.4;       // Climate Value at Risk alto
  } 
  // Si es sector 'limpio' o neutral (Green/Neutral Asset)
  else if (['Technology', 'Healthcare', 'Life Sciences'].includes(sector)) {
    jump_prob = 2.1;
    expected_drop = 8.0;
    cvar_95 = 5.5;
  } 
  // Sectores en transición
  else {
    jump_prob = 9.5;
    expected_drop = 18.0;
    cvar_95 = 14.2;
  }

  // Inyectamos las variables matemáticas simuladas al JSON
  item.json.jump_prob = jump_prob;
  item.json.expected_drop = expected_drop;
  item.json.cvar_95 = cvar_95;
}

return items;

